import{_ as e}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{B as t,c as i,f as l,q as s,D as p,O as r,g as o}from"./chunks/runtime-core.esm-bundler.DoiTk7Jm.js";const P=JSON.parse('{"title":"什么是MCP协议","description":"","frontmatter":{},"headers":[],"relativePath":"column/AIFuture/基础认知/什么是MCP协议.md","filePath":"column/AIFuture/基础认知/什么是MCP协议.md","lastUpdated":1782975799000}'),d={name:"column/AIFuture/基础认知/什么是MCP协议.md"};function c(u,a,h,b,m,g){const n=t("ArticleMetadata");return l(),i("div",null,[a[0]||(a[0]=s("h1",{id:"什么是mcp协议",tabindex:"-1"},[o("什么是MCP协议 "),s("a",{class:"header-anchor",href:"#什么是mcp协议","aria-label":'Permalink to "什么是MCP协议"'},"​")],-1)),p(n),a[1]||(a[1]=r(`<p>你有没有遇到过这种场景：</p><p>你跟 AI 说&quot;帮我查一下数据库里这个用户的订单&quot;，它说&quot;抱歉，我没法直接访问数据库&quot;。</p><p>你说&quot;帮我把这段代码提交到 GitHub&quot;，它说&quot;抱歉，我操作不了你的 Git&quot;。</p><p>你不禁想问：你那么聪明，怎么连这么简单的事都做不了？</p><p>问题不在于模型笨，而在于<strong>它被隔离在一个沙箱里，碰不到外部世界</strong>。它能思考、能推理、能生成，但数据库、文件系统、GitHub、企业内部 API——这些它统统够不着。</p><p>MCP（Model Context Protocol）就是给这个问题设计的一把&quot;万能插头&quot;。</p><h2 id="mcp-到底是个啥" tabindex="-1">MCP 到底是个啥？ <a class="header-anchor" href="#mcp-到底是个啥" aria-label="Permalink to &quot;MCP 到底是个啥？&quot;">​</a></h2><p>MCP 是 Anthropic 在 2024 年底推出的一个协议标准。一句话解释：</p><blockquote><p>让 AI 以统一、安全的方式调用外部工具和数据。</p></blockquote><p>你可以把它理解成 AI 世界的&quot;USB-C 接口&quot;——不管后面接的是数据库、GitHub、本地文件还是企业内部系统，前面这套交互方式是一样的。</p><h2 id="没有-mcp-的时候有多痛苦" tabindex="-1">没有 MCP 的时候有多痛苦？ <a class="header-anchor" href="#没有-mcp-的时候有多痛苦" aria-label="Permalink to &quot;没有 MCP 的时候有多痛苦？&quot;">​</a></h2><p>在 MCP 出现之前，想让 AI 接入外部系统也不是不行，但基本是各路神仙各显神通：</p><ul><li>每个工具写一套整合逻辑，API 格式五花八门</li><li>安全问题全靠开发者自己兜底</li><li>换一个模型或者换一个工具，推倒重来</li><li>想加一个新能力？改代码改到怀疑人生</li></ul><p>MCP 干的事很简单：<strong>把这些乱七八糟的对接方式统一成一套标准</strong>。就像 HTTP 统一了网页访问一样，MCP 想统一 AI 跟外部世界的交互。</p><h2 id="架构长什么样" tabindex="-1">架构长什么样？ <a class="header-anchor" href="#架构长什么样" aria-label="Permalink to &quot;架构长什么样？&quot;">​</a></h2><p>不复杂，五层：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你（用户）</span></span>
<span class="line"><span> ↓</span></span>
<span class="line"><span>大模型（LLM）—— 负责理解意图、决定要不要调工具</span></span>
<span class="line"><span> ↓</span></span>
<span class="line"><span>MCP Client —— 发起请求、管理上下文</span></span>
<span class="line"><span> ↓</span></span>
<span class="line"><span>MCP Server —— 提供具体能力、执行真实逻辑</span></span>
<span class="line"><span> ↓</span></span>
<span class="line"><span>外部系统 —— 数据库、GitHub、文件、企业 API</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="工作流程也很直观" tabindex="-1">工作流程也很直观 <a class="header-anchor" href="#工作流程也很直观" aria-label="Permalink to &quot;工作流程也很直观&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 你说&quot;帮我查一下上个月的销售数据&quot;</span></span>
<span class="line"><span>2. LLM 理解了：需要查数据库</span></span>
<span class="line"><span>3. 通过 MCP Client 发请求给 MCP Server</span></span>
<span class="line"><span>4. MCP Server 执行 SQL 查询</span></span>
<span class="line"><span>5. 数据返回给 LLM</span></span>
<span class="line"><span>6. LLM 整理成你想要的格式输出</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>整个过程你不需要关心中间怎么接的，对用户来说就是&quot;问了就答了&quot;。</p><h2 id="mcp-能干什么" tabindex="-1">MCP 能干什么？ <a class="header-anchor" href="#mcp-能干什么" aria-label="Permalink to &quot;MCP 能干什么？&quot;">​</a></h2><h3 id="_1-统一工具调用" tabindex="-1">1. 统一工具调用 <a class="header-anchor" href="#_1-统一工具调用" aria-label="Permalink to &quot;1. 统一工具调用&quot;">​</a></h3><p>以前调个工具，每个工具的格式、鉴权方式、返回结构都不一样。MCP 把这个标准化了：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;get_user&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;input&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">123</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>模型输出这种结构化指令，MCP Server 负责执行。你不用关心 Server 后面是 MySQL 还是 PostgreSQL。</p><h3 id="_2-上下文管理" tabindex="-1">2. 上下文管理 <a class="header-anchor" href="#_2-上下文管理" aria-label="Permalink to &quot;2. 上下文管理&quot;">​</a></h3><p>不是所有数据都适合拼进 prompt 里。MCP 支持：</p><ul><li>结构化传入上下文（用户信息、项目信息、权限等）</li><li>数据隔离（该谁看谁看）</li><li>按需加载（不用把所有数据一次性灌进去）</li></ul><h3 id="_3-随便扩展" tabindex="-1">3. 随便扩展 <a class="header-anchor" href="#_3-随便扩展" aria-label="Permalink to &quot;3. 随便扩展&quot;">​</a></h3><p>任何东西都可以封装成 MCP Server：</p><ul><li>文件系统操作</li><li>Git 操作</li><li>命令行执行</li><li>数据库查询</li><li>第三方 API（飞书、企业微信、Jira...）</li></ul><p>加一个新能力 = 接入一个新的 MCP Server，不用动其他部分的代码。</p><h2 id="两个实际的例子" tabindex="-1">两个实际的例子 <a class="header-anchor" href="#两个实际的例子" aria-label="Permalink to &quot;两个实际的例子&quot;">​</a></h2><h3 id="场景一-让-ai-帮你管-github" tabindex="-1">场景一：让 AI 帮你管 GitHub <a class="header-anchor" href="#场景一-让-ai-帮你管-github" aria-label="Permalink to &quot;场景一：让 AI 帮你管 GitHub&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你说：帮我建一个项目仓库，初始化代码，提交上去</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>AI 背后做的事：</p><ol><li>调用 GitHub MCP Server → 创建 repo</li><li>生成代码</li><li>通过 MCP → 提交到仓库</li><li>创建 PR</li></ol><p>全程你就在对话窗口里看着它干完。</p><h3 id="场景二-ide-里修-bug" tabindex="-1">场景二：IDE 里修 bug <a class="header-anchor" href="#场景二-ide-里修-bug" aria-label="Permalink to &quot;场景二：IDE 里修 bug&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你说：帮我修这个 bug</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>AI 在 IDE 里做的事：</p><ol><li>通过文件系统 MCP → 读取项目文件</li><li>分析问题</li><li>修改代码</li><li>生成 diff</li><li>通过 Git MCP → 提交</li></ol><p>本质上和你自己改代码的流程一模一样，只是执行的人换成了 AI。</p><p>两个场景底层逻辑是一致的：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AI 做决策 → MCP 做连接 → 工具做执行 → 返回结果</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="mcp-和-function-calling-是什么关系" tabindex="-1">MCP 和 Function Calling 是什么关系？ <a class="header-anchor" href="#mcp-和-function-calling-是什么关系" aria-label="Permalink to &quot;MCP 和 Function Calling 是什么关系？&quot;">​</a></h2><p>经常有人把这两个搞混，其实很好区分：</p><table tabindex="0"><thead><tr><th></th><th>Function Calling</th><th>MCP</th></tr></thead><tbody><tr><td>工具调用</td><td>✅</td><td>✅</td></tr><tr><td>协议标准化</td><td>❌（各搞各的）</td><td>✅（统一标准）</td></tr><tr><td>跨系统</td><td>❌</td><td>✅</td></tr><tr><td>安全控制</td><td>靠开发者自己</td><td>协议层内置</td></tr></tbody></table><p>一句话说明白：</p><blockquote><p>Function Calling 是模型的一种<strong>能力</strong>——它能输出&quot;我要调这个函数&quot;。</p><p>MCP 是一套<strong>体系</strong>——定义了模型怎么发现工具、怎么调、怎么管权限、怎么处理结果。</p></blockquote><p>Function Calling 相当于&quot;会开车&quot;，MCP 相当于&quot;交通规则 + 驾校考核标准&quot;。你会开车不代表路上不会出事，有了规则和标准才能规模化上路。</p><h2 id="为什么这件事重要" tabindex="-1">为什么这件事重要？ <a class="header-anchor" href="#为什么这件事重要" aria-label="Permalink to &quot;为什么这件事重要？&quot;">​</a></h2><p>MCP 在解决一个根本问题：<strong>AI 不能永远活在对话框里</strong>。</p><p>你让 AI 写代码，它写完了，然后呢？你手动复制粘贴到 IDE？手动跑测试？手动部署？</p><p>MCP 让 AI 从&quot;能说&quot;变成&quot;能做&quot;。这个转变的意义，可能比模型本身参数翻一倍还要大。</p><hr><blockquote><p>MCP 就是 AI 通向现实世界的那根数据线。插上了，它就不只是个聊天的，而是个能干活的。</p></blockquote><hr><p><em>延伸阅读</em></p><ul><li><a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">Model Context Protocol 官方文档</a></li><li><a href="https://www.anthropic.com/news/model-context-protocol" target="_blank" rel="noreferrer">Anthropic：Introducing the Model Context Protocol</a></li><li><a href="https://github.com/modelcontextprotocol" target="_blank" rel="noreferrer">MCP GitHub</a></li></ul>`,60))])}const q=e(d,[["render",c]]);export{P as __pageData,q as default};
